/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:native_device_orientation/native_device_orientation.dart';

// Project imports:
import 'package:baseball_detector_flutter/gen/assets.gen.dart';
import 'package:baseball_detector_flutter/providers/dark_mode_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/screen_orientation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';

class LoginLayout extends HookConsumerWidget {
  const LoginLayout({
    super.key,
    required this.child,
  });

  final Widget? child;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final isDarkMode = ref.watch(darkModeProvider);

    final width = context.screenWidth;

    useEffectOnce(
      () {
        ScreenOrientation.lock([NativeDeviceOrientation.portraitUp]);

        return () => ScreenOrientation.setDefault();
      },
    );

    return Scaffold(
      resizeToAvoidBottomInset: true,
      body: SingleChildScrollView(
        reverse: true,
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            RepaintBoundary(
              child: SizedBox(
                height: 200,
                child: Assets.images.imgLoginTop.image(
                  width: width,
                  fit: BoxFit.cover,
                ),
              ),
            ),
            RepaintBoundary(
              child: isDarkMode
                  ? Assets.images.imgAppLogoDark.svg(width: 320)
                  : Assets.images.imgAppLogoLight.svg(width: 320),
            ),
            const Gap(24),
            Padding(
              padding: EdgeInsets.fromLTRB(
                28,
                0,
                28,
                32,
              ),
              child: child ?? const SizedBox.shrink(),
            ),
          ],
        ),
      ),
    );
  }
}
